// To parse this JSON data, do
//
//     final tslint = tslintFromJson(jsonString);

import 'dart:convert';

Tslint tslintFromJson(String str) => Tslint.fromJson(json.decode(str));

String tslintToJson(Tslint data) => json.encode(data.toJson());

class Tslint {
    Rules rules;

    Tslint({
        required this.rules,
    });

    factory Tslint.fromJson(Map<String, dynamic> json) => Tslint(
        rules: Rules.fromJson(json["rules"]),
    );

    Map<String, dynamic> toJson() => {
        "rules": rules.toJson(),
    };
}

class Rules {
    bool ban;
    bool className;
    bool eofline;
    List<dynamic> indent;
    List<dynamic> commentFormat;
    bool curly;
    bool forin;
    bool labelPosition;
    bool noArg;
    bool noAny;
    bool jsdocFormat;
    List<dynamic> semicolon;
    bool noDuplicateVariable;
    List<dynamic> noConsecutiveBlankLines;
    List<dynamic> noConsole;
    bool noDebugger;
    bool noEval;
    List<dynamic> noInferrableTypes;
    bool noShadowedVariable;
    bool noStringLiteral;
    bool noTrailingWhitespace;
    bool noUnusedExpression;
    List<dynamic> oneLine;
    List<dynamic> typedefWhitespace;
    bool noSwitchCaseFallThrough;
    List<dynamic> quotemark;
    List<dynamic> tripleEquals;
    List<dynamic> variableName;
    List<dynamic> objectLiteralKeyQuotes;

    Rules({
        required this.ban,
        required this.className,
        required this.eofline,
        required this.indent,
        required this.commentFormat,
        required this.curly,
        required this.forin,
        required this.labelPosition,
        required this.noArg,
        required this.noAny,
        required this.jsdocFormat,
        required this.semicolon,
        required this.noDuplicateVariable,
        required this.noConsecutiveBlankLines,
        required this.noConsole,
        required this.noDebugger,
        required this.noEval,
        required this.noInferrableTypes,
        required this.noShadowedVariable,
        required this.noStringLiteral,
        required this.noTrailingWhitespace,
        required this.noUnusedExpression,
        required this.oneLine,
        required this.typedefWhitespace,
        required this.noSwitchCaseFallThrough,
        required this.quotemark,
        required this.tripleEquals,
        required this.variableName,
        required this.objectLiteralKeyQuotes,
    });

    factory Rules.fromJson(Map<String, dynamic> json) => Rules(
        ban: json["ban"],
        className: json["class-name"],
        eofline: json["eofline"],
        indent: List<dynamic>.from(json["indent"].map((x) => x)),
        commentFormat: List<dynamic>.from(json["comment-format"].map((x) => x)),
        curly: json["curly"],
        forin: json["forin"],
        labelPosition: json["label-position"],
        noArg: json["no-arg"],
        noAny: json["no-any"],
        jsdocFormat: json["jsdoc-format"],
        semicolon: List<dynamic>.from(json["semicolon"].map((x) => x)),
        noDuplicateVariable: json["no-duplicate-variable"],
        noConsecutiveBlankLines: List<dynamic>.from(json["no-consecutive-blank-lines"].map((x) => x)),
        noConsole: List<dynamic>.from(json["no-console"].map((x) => x)),
        noDebugger: json["no-debugger"],
        noEval: json["no-eval"],
        noInferrableTypes: List<dynamic>.from(json["no-inferrable-types"].map((x) => x)),
        noShadowedVariable: json["no-shadowed-variable"],
        noStringLiteral: json["no-string-literal"],
        noTrailingWhitespace: json["no-trailing-whitespace"],
        noUnusedExpression: json["no-unused-expression"],
        oneLine: List<dynamic>.from(json["one-line"].map((x) => x)),
        typedefWhitespace: List<dynamic>.from(json["typedef-whitespace"].map((x) => x)),
        noSwitchCaseFallThrough: json["no-switch-case-fall-through"],
        quotemark: List<dynamic>.from(json["quotemark"].map((x) => x)),
        tripleEquals: List<dynamic>.from(json["triple-equals"].map((x) => x)),
        variableName: List<dynamic>.from(json["variable-name"].map((x) => x)),
        objectLiteralKeyQuotes: List<dynamic>.from(json["object-literal-key-quotes"].map((x) => x)),
