        "class-name": className,
        "eofline": eofline,
        "indent": List<dynamic>.from(indent.map((x) => x)),
        "comment-format": List<dynamic>.from(commentFormat.map((x) => x)),
        "curly": curly,
        "forin": forin,
        "label-position": labelPosition,
        "no-arg": noArg,
        "no-any": noAny,
        "jsdoc-format": jsdocFormat,
        "semicolon": List<dynamic>.from(semicolon.map((x) => x)),
        "no-duplicate-variable": noDuplicateVariable,
        "no-consecutive-blank-lines": List<dynamic>.from(noConsecutiveBlankLines.map((x) => x)),
        "no-console": List<dynamic>.from(noConsole.map((x) => x)),
        "no-debugger": noDebugger,
        "no-eval": noEval,
        "no-inferrable-types": List<dynamic>.from(noInferrableTypes.map((x) => x)),
        "no-shadowed-variable": noShadowedVariable,
        "no-string-literal": noStringLiteral,
        "no-trailing-whitespace": noTrailingWhitespace,
