class TypedefWhitespaceClass {
    String callSignature;
    String indexSignature;
    String parameter;
    String propertyDeclaration;
    String variableDeclaration;

    TypedefWhitespaceClass({
        required this.callSignature,
        required this.indexSignature,
        required this.parameter,
        required this.propertyDeclaration,
        required this.variableDeclaration,
    });

    factory TypedefWhitespaceClass.fromJson(Map<String, dynamic> json) => TypedefWhitespaceClass(
        callSignature: json["call-signature"],
        indexSignature: json["index-signature"],
        parameter: json["parameter"],
        propertyDeclaration: json["property-declaration"],
        variableDeclaration: json["variable-declaration"],
    );

    Map<String, dynamic> toJson() => {
        "call-signature": callSignature,
        "index-signature": indexSignature,
        "parameter": parameter,
        "property-declaration": propertyDeclaration,
        "variable-declaration": variableDeclaration,
    };
}
